class Solution {
public:
    int minLength(string s) {
        int n = s.size();
        int dp[n + 1];
        dp[0] = 0;
        for (int i = 1; i <= n; i++) {
            dp[i] = i;
            if (i >= 2 && (s[i - 1] == 'B' && s[i - 2] == 'A' || s[i - 1] == 'D' && s[i - 2] == 'C')) {
                dp[i] = min(dp[i], dp[i - 2]);
            }
            if (i >= 1 && (s[i - 1] == 'B' && s[i - 2] == 'C' || s[i - 1] == 'D' && s[i - 2] == 'A')) {
                dp[i] = min(dp[i], dp[i - 1]);
            }
        }
        return dp[n];
    }
};
